from typing import List

class Solution:
    def countInterestingSubarrays(self, nums: List[int], modulo: int, k: int) -> int:
        prefix_counts = [0]
        for num in nums:
            prefix_counts.append(prefix_counts[-1] + (1 if num % modulo == k else 0))

        count = 0
        for i in range(len(prefix_counts)):
            for j in range(i + 1, len(prefix_counts)):
                if (prefix_counts[j] - prefix_counts[i]) % modulo == k:
                    count += 1
        return count
